function solve(c, connections, queries) {
    const parent = new Array(c + 1).fill(0).map((_, i) => i);
    const rank = new Array(c + 1).fill(0);
    const online = new Array(c + 1).fill(true);
    const minNode = new Array(c + 1).fill(0).map((_, i) => i);

    function find(u) {
        if (parent[u] !== u) {
            parent[u] = find(parent[u]);
        }
        return parent[u];
    }

    function union(u, v) {
        let rootU = find(u);
        let rootV = find(v);
        if (rootU === rootV) return;
        if (rank[rootU] > rank[rootV]) {
            parent[rootV] = rootU;
            minNode[rootU] = Math.min(minNode[rootU], minNode[rootV]);
        } else if (rank[rootU] < rank[rootV]) {
            parent[rootU] = rootV;
            minNode[rootV] = Math.min(minNode[rootV], minNode[rootU]);
        } else {
            parent[rootV] = rootU;
            rank[rootU]++;
            minNode[rootU] = Math.min(minNode[rootU], minNode[rootV]);
        }
    }

    for (const [u, v] of connections) {
        union(u, v);
    }

    const result = [];
    for (const [type, x] of queries) {
        if (type === 1) {
            const root = find(x);
            if (online[x]) {
                result.push(x);
            } else {
                let currentMin = Infinity;
                let found = false;
                // To optimize, we can track the min online node per set
                // But with large c, we need a better approach
                // Here's a workaround using the minNode array, but it's not sufficient
                // So we need to maintain a separate structure for min online node per set
                // For the sake of this problem, we'll proceed with a brute-force approach (not efficient for large c)
                let minOnline = -1;
                for (let i = 1; i <= c; i++) {
